@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam class {
  BackgroundColor #F2F2F2
  BorderColor #333333
  ArrowColor #333333
}

class Main {
  int month
  int day
  --
  DateTime()
  getMonthOfYear()
  getDayOfWeek()
}

class Month {
  String name
  --
  ToText()
}

class Day {
  String name
  --
  ToText()
}

Month -up-|> Main
Day -up-|> Main
@enduml
